 918→router.post('/update-username', requireAuth, async (req, res) => {
 919→    const userId = req.userId;
 920→    const { username } = req.body;
 921→
 922→    if (!username || typeof username !== 'string') {
 923→        return res.status(400).json({ error: 'username is required' });
 924→    }
 925→
 926→    const trimmed = username.trim();
 927→    if (trimmed.length < 3 || trimmed.length > 50) {
 928→        return res.status(400).json({ error: 'username must be 3-50 characters' });
 929→    }
 930→
 931→    if (!/^[a-zA-Z0-9-]+$/.test(trimmed)) {
 932→        return res.status(400).json({ error: 'username can only contain letters, numbers, and hyphens' });
 933→    }
 934→
 935→    const normalized = trimmed.toLowerCase();
 936→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
 937→    if (RESERVED_WORDS.includes(normalized)) {
 938→        return res.status(400).json({ error: 'this username is reserved' });
 939→    }
 940→
 941→    // Check uniqueness
 942→    const { data: existing } = await supabase
 943→        .from('users')
 944→        .select('id')
 945→        .ilike('username', normalized)
 946→        .neq('id', userId)
 947→        .limit(1);
 948→
 949→    if (existing && existing.length > 0) {
 950→        return res.status(409).json({ error: 'username is already taken' });
 951→    }
 952→
 953→    const { error: updateError } = await supabase
 954→        .from('users')
 955→        .update({ username: trimmed.toLowerCase() })
 956→        .eq('id', userId);
 957→
 958→    if (updateError) {
 959→        console.error('update-username error:', updateError.message);
 960→        return res.status(500).json({ error: 'failed to update username' });
 961→    }
 962→
 963→    return res.status(200).json({ message: 'success', username: trimmed.toLowerCase() });
 964→});
